class Solution:
    def countPalindromicSubsequence(self, s):
        """
        :type s: str
        :rtype: int
        """
        # For each char, find first and last occurrence
        first = {}
        last = {}

        for i, char in enumerate(s):
            if char not in first:
                first[char] = i
            last[char] = i

        result = 0

        # For each char with gap >= 2, count unique middle chars
        for char in first:
            if last[char] - first[char] >= 2:
                # Count unique chars between first and last
                middle_chars = set(s[first[char] + 1 : last[char]])
                result += len(middle_chars)

        return result
